#!/usr/bin/env php
<?php
declare(strict_types=1);
use App\Core\Cloud\CloudS3Service;use App\Core\Database\PdoFactory;
$root=dirname(__DIR__);require_once $root.'/vendor/autoload.php';$app=require $root.'/bootstrap/app.php';$config=is_array($app['config']??null)?$app['config']:[];$o=getopt('', ['tenant:','user:','file:','head-object']);$t=(int)($o['tenant']??0);$u=(int)($o['user']??0);$id=(int)($o['file']??0);
$pdo=PdoFactory::make((array)($config['database']??[]));$s=$pdo->prepare('SELECT id,original_name,status,found_in_s3,checksum_sha256,etag,s3_key FROM cloud_files WHERE tenant_id=:t AND user_id=:u AND id=:id LIMIT 1');$s->execute([':t'=>$t,':u'=>$u,':id'=>$id]);$r=$s->fetch(PDO::FETCH_ASSOC);if(!is_array($r)){echo json_encode(['ok'=>false,'message'=>'Archivo no encontrado.'],JSON_PRETTY_PRINT).PHP_EOL;exit(1);} $exp='users/'.$u.'/uploads/';$scope=CloudPath::keyScope($u,(string)$r['s3_key']);$out=['ok'=>true,'file_id'=>(int)$r['id'],'original_name'=>(string)$r['original_name'],'status'=>(string)$r['status'],'found_in_s3'=>(int)$r['found_in_s3'],'checksum_present'=>trim((string)($r['checksum_sha256']??''))!=='','etag_present'=>trim((string)($r['etag']??''))!=='','key_scope'=>$scope,'key_prefix_expected'=>$exp,'duplicated_user_segment'=>$scope==='duplicated_user_segment'];if(array_key_exists('head-object',$o)){ $h=(new CloudS3Service($config))->getObject((string)$r['s3_key']); $out['head_object_ok']=(bool)($h['ok']??false);} echo json_encode($out,JSON_PRETTY_PRINT|JSON_UNESCAPED_UNICODE).PHP_EOL;
